INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('red_flags','tension_pneumothorax','{"نیوموتھوریکس","ہوا سینے میں","سانس نہ آنا","صدمہ"}','ٹینشن نیوموتھوریکس','## ٹینشن نیوموتھوریکس\n\n**🚨 فوری ایمرجنسی:**\n- شدید سانس کی تکلیف\n- ایک طرف سانس کی آواز غائب\n- ٹریکیا مخالف طرف\n- گردن کی رگیں پھولی ہوئی\n\n**فوری علاج:** سوئی سے ہوا نکالنا (2nd intercostal space)','ur','ATLS',10,true),
('red_flags','placental_abruption','{"نال الگ","حمل میں خون","پیٹ درد حمل","پلیسنٹا"}','نال کا الگ ہونا','## نال کا الگ ہونا\n\n**🚨 فوری ایمرجنسی:**\n- حمل میں اندام نہانی سے خون\n- مسلسل پیٹ درد\n- بچہ دانی سخت\n- بچے کی دل کی دھڑکن غیر معمولی\n\n**فوری:** IV لائن، خون کا انتظام، فوری سیزیرین','ur','RCOG',10,true),
('red_flags','acute_glaucoma','{"گلوکوما","آنکھ درد","بصارت کم","آنکھ سرخ"}','شدید گلوکوما','## شدید گلوکوما\n\n**🚨 فوری:**\n- آنکھ میں شدید درد\n- بصارت دھندلی/رنگین حلقے\n- متلی/قے\n- آنکھ سخت اور سرخ\n\n**علاج:** ٹائمولول قطرے + IV مینیٹول + فوری آنکھوں کے ڈاکٹر','ur','AAO',10,true),
('red_flags','aortic_dissection','{"شریان پھٹنا","سینے میں پھٹنے والا درد","کمر درد شدید","اورٹک"}','شریان اورطی کا پھٹنا','## شریان اورطی کا پھٹنا\n\n**🚨 فوری:**\n- سینے/کمر میں چیرنے والا درد\n- دونوں بازوؤں میں بلڈ پریشر مختلف\n- نبض کا فرق\n\n**فوری:** بلڈ پریشر کنٹرول، CT انجیو، سرجری','ur','AHA',10,true),
('red_flags','status_epilepticus','{"مسلسل دورے","اسٹیٹس","مرگی شدید","تشنج"}','مسلسل مرگی کے دورے','## اسٹیٹس ایپی لیپٹیکس\n\n**🚨 فوری (دورہ >5 منٹ):**\n- ABC یقینی بنائیں\n- ڈائی ایزیپام 10mg IV/PR\n- دوبارہ: 5 منٹ بعد\n- پھر: فینیٹوئن 20mg/kg IV\n\n**خطرہ:** دماغی نقصان، موت','ur','ILAE',10,true),
('red_flags','severe_sepsis','{"سیپسس","خون میں زہر","انفیکشن شدید","سیپٹک شاک"}','شدید سیپسس','## شدید سیپسس\n\n**🚨 qSOFA:** ≥2\n- بلڈ پریشر <100\n- سانس >22/منٹ\n- ذہنی حالت بدلی\n\n**فوری علاج (1 گھنٹے میں):**\n- بلڈ کلچر\n- IV اینٹی بائیوٹکس\n- 30mL/kg سیلائن\n- لیکٹیٹ چیک کریں','ur','SSC',10,true),
('red_flags','pulmonary_edema','{"پھیپھڑوں میں پانی","سانس تکلیف","دل کی ناکامی","جھاگ دار بلغم"}','پھیپھڑوں میں پانی','## پلمونری ایڈیما\n\n**🚨 فوری:**\n- شدید سانس کی تکلیف\n- جھاگ دار/گلابی بلغم\n- بیٹھ کر سانس لینا\n\n**علاج:**\n- آکسیجن\n- فیوروسیمائیڈ 40-80mg IV\n- GTN سب لنگوئل\n- مریض کو بٹھائیں','ur','ESC',10,true),
('red_flags','ruptured_ectopic','{"حمل خارج رحم","اندام نہانی سے خون","پیٹ درد شدید","ایکٹوپک"}','حمل خارج رحم پھٹنا','## حمل خارج رحم\n\n**🚨 فوری:**\n- پیٹ کے نچلے حصے میں شدید درد\n- اندام نہانی سے خون آنا\n- چکر/بے ہوشی\n- حمل ٹیسٹ مثبت\n\n**فوری:** IV لائن، خون کا انتظام، فوری سرجری','ur','RCOG',10,true),
('red_flags','acute_abdomen','{"شدید پیٹ درد","اپینڈکس","انسداد","پیریٹونائٹس"}','شدید پیٹ درد','## شدید پیٹ (Acute Abdomen)\n\n**🚨 سرجیکل ایمرجنسی:**\n- پیٹ سخت (rigidity)\n- rebound tenderness\n- قے + اجابت بند\n\n**وجوہات:** اپینڈکس، السر پھٹنا، انسداد\n**فوری:** NPO، IV سیلائن، سرجن','ur','Custom',10,true),
('red_flags','hypertensive_emergency','{"بلڈ پریشر بہت زیادہ","ہائپرٹینسو","سر درد شدید","نکسیر"}','ہائپرٹینسو ایمرجنسی','## بلڈ پریشر بحران (>180/120)\n\n**🚨 اعضاء کو نقصان:**\n- شدید سر درد + دھندلی نظر\n- سینے میں درد\n- سانس کی تکلیف\n- ناک سے خون\n\n**علاج:** لیبیٹالول IV یا نائٹروپروسائیڈ\n**ہدف:** 1 گھنٹے میں 25% کمی','ur','AHA',10,true),
('red_flags','hypoglycemia','{"شوگر کم","ہائپوگلائسیمیا","چکر","پسینہ","کانپنا"}','خون میں شوگر کم','## ہائپوگلائسیمیا (<70 mg/dL)\n\n**🚨 علامات:**\n- کانپنا، پسینہ، بھوک\n- الجھن، بے ہوشی\n- دورے\n\n**علاج:**\n- ہوش میں: 15-20g گلوکوز (رس/چینی)\n- بے ہوش: 50mL D50 IV یا گلوکاگون 1mg IM\n- 15 منٹ بعد دوبارہ چیک','ur','ADA',10,true),
('red_flags','anaphylaxis','{"شدید الرجی","انافلیکسس","سانس بند","سوجن"}','شدید الرجی (انافلیکسس)','## انافلیکسس\n\n**🚨 فوری:**\n- چہرے/گلے کی سوجن\n- سانس لینے میں دشواری\n- بلڈ پریشر گرنا\n- پورے جسم پر دانے\n\n**علاج:**\n- ایپی نیفرین 0.5mg IM (ران)\n- ہر 5-15 منٹ دہرائیں\n- IV سیلائن\n- ہائیڈروکورٹیسون 200mg IV','ur','WAO',10,true),
('red_flags','testicular_torsion','{"خصیے میں درد","ٹیسٹیکولر","مروڑ","فوری سرجری"}','خصیے کا مروڑ','## خصیے کا مروڑ\n\n**🚨 فوری (6 گھنٹے کے اندر سرجری):**\n- اچانک شدید خصیے کا درد\n- متلی/قے\n- خصیہ اوپر اٹھا ہوا\n- Cremasteric reflex غائب\n\n**⚠️ سرجری میں تاخیر = خصیہ ضائع**','ur','AUA',10,true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('drug_reference','doxycycline','{"ڈوکسی سائکلین","اینٹی بائیوٹک","ملیریا وقایہ","مہاسے"}','ڈوکسی سائکلین','## ڈوکسی سائکلین\n\n**استعمال:** انفیکشنز، مہاسے، ملیریا وقایہ\n**خوراک:** 100mg دن میں 1-2 بار\n**⚠️ دودھ/اینٹاسڈ کے ساتھ نہ لیں\n**ضمنی اثرات:** معدے کی خرابی، سورج سے حساسیت\n**ممنوع:** حاملہ، بچے <8 سال','ur','BNF',7,true),
('drug_reference','ranitidine','{"رینیٹیڈین","تیزابیت","معدہ","السر"}','رینیٹیڈین','## رینیٹیڈین\n\n**استعمال:** تیزابیت، السر، GERD\n**خوراک:** 150mg دن میں 2 بار یا 300mg رات کو\n**ضمنی اثرات:** سر درد، قبض\n**⚠️ نوٹ:** بعض ممالک میں واپس لیا گیا (NDMA)','ur','BNF',7,true),
('drug_reference','loperamide','{"لوپیرامائیڈ","دست بند","اسہال","اموٹیل"}','لوپیرامائیڈ','## لوپیرامائیڈ\n\n**استعمال:** شدید اسہال\n**خوراک:** پہلے 4mg پھر ہر اسہال کے بعد 2mg (زیادہ سے زیادہ 16mg/دن)\n**⚠️ خونی اسہال میں استعمال نہ کریں\n**ممنوع:** 2 سال سے کم عمر بچے','ur','BNF',7,true),
('drug_reference','ors','{"ORS","نمکول","جفاف روکنا","اسہال"}','ORS (نمکول)','## ORS\n\n**استعمال:** جفاف کا علاج اور روک تھام\n**تیاری:** 1 پاؤچ + 1 لیٹر صاف پانی\n**خوراک:** ہر اسہال کے بعد: <2 سال 50-100mL، بڑے 200mL+\n**⚠️ 24 گھنٹے بعد تازہ بنائیں','ur','WHO',7,true),
('drug_reference','ferrous_sulfate','{"فیرس سلفیٹ","آئرن","خون کی کمی","حدید"}','فیرس سلفیٹ','## فیرس سلفیٹ\n\n**استعمال:** آئرن کی کمی سے خون کی کمی\n**خوراک:** 200mg دن میں 2-3 بار خالی پیٹ\n**⚠️ وٹامن C کے ساتھ جذب بہتر\n**ضمنی اثرات:** قبض، سیاہ پاخانہ، معدے کی تکلیف\n**مدت:** کم از کم 3 ماہ','ur','WHO',7,true),
('drug_reference','folic_acid','{"فولک ایسڈ","حمل","خون","B9"}','فولک ایسڈ','## فولک ایسڈ\n\n**استعمال:** حمل، خون کی کمی\n**خوراک:**\n- حمل سے پہلے/دوران: 5mg روزانہ\n- خون کی کمی: 5mg روزانہ\n**⚠️ حمل سے 3 ماہ پہلے شروع کریں (عیب دانی کی روک تھام)','ur','WHO',7,true),
('drug_reference','vitamin_d','{"وٹامن ڈی","ہڈیاں","سورج","کیلشیم"}','وٹامن ڈی','## وٹامن ڈی\n\n**استعمال:** ہڈیوں کی مضبوطی، کمی کا علاج\n**خوراک:**\n- روزانہ: 1000-2000 IU\n- شدید کمی: 50,000 IU ہفتہ وار 8-12 ہفتے\n**⚠️ زیادتی سے کیلشیم بڑھ سکتا ہے','ur','NIH',7,true),
('drug_reference','calcium','{"کیلشیم","ہڈیاں","آسٹیوپوروسس","دودھ"}','کیلشیم','## کیلشیم\n\n**استعمال:** ہڈیوں کی کمزوری، حمل\n**خوراک:** 500-1000mg روزانہ (وٹامن D کے ساتھ)\n**⚠️ آئرن سے الگ وقت میں لیں\n**ضمنی اثرات:** قبض، پیٹ پھولنا','ur','NOF',7,true),
('drug_reference','montelukast','{"مونٹیلوکاسٹ","دمہ","الرجی","سنگولیئر"}','مونٹیلوکاسٹ','## مونٹیلوکاسٹ\n\n**استعمال:** دمہ، الرجی ناک\n**خوراک:**\n- بالغ: 10mg رات کو\n- 6-14 سال: 5mg\n- 2-5 سال: 4mg\n**⚠️ موڈ/رویے میں تبدیلی پر توجہ دیں','ur','BNF',7,true),
('drug_reference','chlorpheniramine','{"کلورفینیرامین","الرجی","اینٹی ہسٹامین","چھینکیں"}','کلورفینیرامین','## کلورفینیرامین\n\n**استعمال:** الرجی، نزلہ، چھتے\n**خوراک:** 4mg ہر 4-6 گھنٹے (زیادہ سے زیادہ 24mg/دن)\n**⚠️ نیند آتی ہے - گاڑی نہ چلائیں\n**ممنوع:** نوزائیدہ','ur','BNF',7,true),
('drug_reference','domperidone','{"ڈومپیریڈون","متلی","قے","ہاضمہ"}','ڈومپیریڈون','## ڈومپیریڈون\n\n**استعمال:** متلی، قے، بدہضمی\n**خوراک:** 10mg دن میں 3 بار کھانے سے پہلے\n**⚠️ زیادہ سے زیادہ 7 دن\n**ضمنی اثرات:** سر درد، خشک منہ\n**ممنوع:** دل کے مریض','ur','BNF',7,true),
('drug_reference','hyoscine','{"ہائیوسین","پیٹ مروڑ","بسکوپان","درد پیٹ"}','ہائیوسین (بسکوپان)','## ہائیوسین بیوٹائل بروومائیڈ\n\n**استعمال:** پیٹ کے مروڑ، آنتوں کا درد\n**خوراک:** 10-20mg دن میں 3-4 بار\n**ضمنی اثرات:** خشک منہ، دھندلی نظر\n**⚠️ گلوکوما میں ممنوع','ur','BNF',7,true),
('drug_reference','cetirizine','{"سیٹریزین","الرجی","چھتے","ناک بہنا"}','سیٹریزین','## سیٹریزین\n\n**استعمال:** الرجی، چھتے، ناک کی الرجی\n**خوراک:** 10mg روزانہ ایک بار\n**بچے 2-6 سال:** 5mg\n**⚠️ کم نیند آتی ہے (نئی نسل)\n**محفوظ:** حمل (زمرہ B)','ur','BNF',7,true),
('drug_reference','pantoprazole','{"پینٹوپرازول","تیزابیت","معدے کا السر","PPI"}','پینٹوپرازول','## پینٹوپرازول\n\n**استعمال:** تیزابیت، GERD، السر\n**خوراک:** 40mg صبح خالی پیٹ\n**مدت:** 4-8 ہفتے\n**⚠️ طویل استعمال سے: میگنیشیم کمی، ہڈی کمزوری\n**کھانے سے 30 منٹ پہلے لیں','ur','BNF',7,true),
('drug_reference','ceftriaxone','{"سیفٹریکسون","اینٹی بائیوٹک","انجکشن","شدید انفیکشن"}','سیفٹریکسون','## سیفٹریکسون\n\n**استعمال:** شدید انفیکشنز، نمونیا، سیپسس\n**خوراک:** 1-2g IV/IM روزانہ\n**بچے:** 50-100mg/kg/دن\n**⚠️ کیلشیم والی IV سے ملا کر نہ دیں\n**ممنوع:** سیفالوسپورین الرجی','ur','BNF',7,true),
('drug_reference','ondansetron','{"اونڈانسیٹرون","قے بند","متلی","کیموتھراپی"}','اونڈانسیٹرون','## اونڈانسیٹرون\n\n**استعمال:** شدید متلی/قے\n**خوراک:** 4-8mg ضرورت کے مطابق (زیادہ سے زیادہ 24mg/دن)\n**IV/IM:** 4mg آہستہ آہستہ\n**⚠️ QT prolongation کا خطرہ\n**حمل:** ڈاکٹر سے مشورہ','ur','BNF',7,true),
('drug_reference','metoclopramide','{"میٹوکلوپرامائیڈ","متلی","قے","ہاضمہ تیز"}','میٹوکلوپرامائیڈ','## میٹوکلوپرامائیڈ\n\n**استعمال:** متلی، قے، معدے کی سستی\n**خوراک:** 10mg دن میں 3 بار\n**⚠️ زیادہ سے زیادہ 5 دن (بالغ)\n**ضمنی اثرات:** غنودگی، بے چینی\n**ممنوع:** <1 سال، مرگی، آنتوں کا انسداد','ur','BNF',7,true);